export default function ProductoPage() {
  const { slug } = useParams();
  const { products } = useAdminStore();
  const product = products.find(p => p.slug === (slug || ''));
  const { addItem } = useCartStore();
  const { addItem: addToWishlist, removeItem: removeFromWishlist, isInWishlist } = useWishlistStore();

  const [selectedImage, setSelectedImage] = useState(0);
  const [quantity, setQuantity] = useState(1);
  const [isZoomed, setIsZoomed] = useState(false);

  if (!product) {
    return (
      <div className="min-h-screen bg-background">
        <Navbar />
        <div className="container mx-auto px-4 py-32 text-center">
          <h1 className="font-display text-3xl font-bold mb-4">Producto no encontrado</h1>
          <Link to="/catalogo">
            <Button>Volver al Catálogo</Button>
          </Link>
        </div>
        <Footer />
      </div>
    );
  }

  const relatedProducts = products.filter(
    (p) => p.category === product.category && p.id !== product.id
  ).slice(0, 4);

  const handleAddToCart = () => {
    addItem(product, quantity);
  };

  const nextImage = () => {
    setSelectedImage((prev) => (prev + 1) % product.images.length);
  };

  const prevImage = () => {
    setSelectedImage((prev) =>
      prev === 0 ? product.images.length - 1 : prev - 1
    );
  };

  return (
    <div className="min-h-screen bg-background">
      <Navbar />
      <CartDrawer />

      <main className="pt-24 pb-16">
        <div className="container mx-auto px-4 lg:px-8">
          {/* Breadcrumb */}
          <nav className="flex items-center space-x-2 text-sm text-muted-foreground mb-8">
            <Link to="/" className="hover:text-primary">Inicio</Link>
            <span>/</span>
            <Link to="/catalogo" className="hover:text-primary">Catálogo</Link>
            <span>/</span>
            <Link to={`/catalogo?categoria=${product.category}`} className="hover:text-primary capitalize">
              {product.category}
            </Link>
            <span>/</span>
            <span className="text-foreground">{product.name}</span>
          </nav>

          <div className="grid lg:grid-cols-2 gap-12">
            {/* Image Gallery */}
            <div className="space-y-4">
              {/* Main Image */}
              <motion.div
                className="relative aspect-square rounded-2xl overflow-hidden bg-muted"
                onMouseEnter={() => setIsZoomed(true)}
                onMouseLeave={() => setIsZoomed(false)}
              >
                <motion.img
                  key={selectedImage}
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  src={product.images[selectedImage]}
                  alt={product.name}
                  className={cn(
                    "w-full h-full object-cover transition-transform duration-500",
                    isZoomed && "scale-125"
                  )}
                />

                {/* Badges */}
                <div className="absolute top-4 left-4 flex flex-col gap-2">
                  {product.discount && (
                    <Badge className="bg-accent text-accent-foreground">
                      -{product.discount}%
                    </Badge>
                  )}
                  {product.newArrival && (
                    <Badge className="bg-forest text-cream">Nuevo</Badge>
                  )}
                </div>

                {/* Navigation Arrows */}
                {product.images.length > 1 && (
                  <>
                    <button
                      onClick={prevImage}
                      className="absolute left-4 top-1/2 -translate-y-1/2 w-10 h-10 rounded-full bg-background/80 backdrop-blur-sm flex items-center justify-center hover:bg-background transition-colors"
                    >
                      <ChevronLeft className="h-5 w-5" />
                    </button>
                    <button
                      onClick={nextImage}
                      className="absolute right-4 top-1/2 -translate-y-1/2 w-10 h-10 rounded-full bg-background/80 backdrop-blur-sm flex items-center justify-center hover:bg-background transition-colors"
                    >
                      <ChevronRight className="h-5 w-5" />
                    </button>
                  </>
                )}
              </motion.div>

              {/* Thumbnails */}
              {product.images.length > 1 && (
                <div className="flex gap-3 overflow-x-auto pb-2">
                  {product.images.map((image, index) => (
                    <button
                      key={index}
                      onClick={() => setSelectedImage(index)}
                      className={cn(
                        "w-20 h-20 rounded-lg overflow-hidden shrink-0 ring-2 ring-offset-2 transition-all",
                        selectedImage === index
                          ? "ring-primary"
                          : "ring-transparent hover:ring-muted"
                      )}
                    >
                      <img
                        src={image}
                        alt={`${product.name} ${index + 1}`}
                        className="w-full h-full object-cover"
                      />
                    </button>
                  ))}
                </div>
              )}
            </div>

            {/* Product Info */}
            <div className="space-y-6">
              <div>
                <span className="text-sm text-muted-foreground uppercase tracking-wider">
                  {product.category}
                </span>
                <h1 className="font-display text-3xl md:text-4xl font-bold mt-2">
                  {product.name}
                </h1>
              </div>

              {/* Rating */}
              <div className="flex items-center gap-3">
                <div className="flex">
                  {[...Array(5)].map((_, i) => (
                    <svg
                      key={i}
                      className={cn(
                        'w-5 h-5',
                        i < Math.floor(product.rating)
                          ? 'text-gold fill-gold'
                          : 'text-muted fill-muted'
                      )}
                      viewBox="0 0 20 20"
                    >
                      <path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" />
                    </svg>
                  ))}
                </div>
                <span className="text-sm text-muted-foreground">
                  {product.rating} ({product.reviewCount} reseñas)
                </span>
              </div>

              {/* Price */}
              <div className="flex items-baseline gap-3">
                <span className="font-display text-3xl font-bold text-primary">
                  {formatPrice(product.price)}
                </span>
                {product.originalPrice && (
                  <span className="text-lg text-muted-foreground line-through">
                    {formatPrice(product.originalPrice)}
                  </span>
                )}
              </div>

              {/* Short Description */}
              <p className="text-muted-foreground">
                {product.shortDescription}
              </p>

              {/* Stock */}
              <div className="flex items-center gap-2">
                {product.stock > 0 ? (
                  <>
                    <Check className="h-4 w-4 text-forest" />
                    <span className="text-sm text-forest">
                      En stock ({product.stock} disponibles)
                    </span>
                  </>
                ) : (
                  <span className="text-sm text-destructive">Agotado</span>
                )}
              </div>

              {/* Quantity & Add to Cart */}
              <div className="flex flex-col sm:flex-row gap-4">
                <div className="flex items-center border border-input rounded-lg">
                  <button
                    onClick={() => setQuantity(Math.max(1, quantity - 1))}
                    className="p-3 hover:bg-muted transition-colors"
                  >
                    <Minus className="h-4 w-4" />
                  </button>
                  <span className="px-6 font-medium">{quantity}</span>
                  <button
                    onClick={() => setQuantity(Math.min(product.stock, quantity + 1))}
                    className="p-3 hover:bg-muted transition-colors"
                  >
                    <Plus className="h-4 w-4" />
                  </button>
                </div>

                <Button
                  size="lg"
                  className="flex-1 bg-primary text-primary-foreground hover:bg-wood-light"
                  onClick={handleAddToCart}
                  disabled={product.stock === 0}
                >
                  <ShoppingCart className="mr-2 h-5 w-5" />
                  Añadir al Carrito
                </Button>

                <Button
                  size="lg"
                  variant="outline"
                  onClick={() => {
                    if (product) {
                      isInWishlist(product.id) ? removeFromWishlist(product.id) : addToWishlist(product);
                    }
                  }}
                  className={cn(
                    "transition-colors",
                    product && isInWishlist(product.id) && "text-red-500 border-red-500 hover:bg-red-50"
                  )}
                >
                  <Heart className={cn("h-5 w-5", product && isInWishlist(product.id) && "fill-current")} />
                </Button>
              </div>

              {/* Benefits */}
              <div className="grid grid-cols-3 gap-4 py-6 border-y border-border">
                <div className="text-center">
                  <Truck className="h-6 w-6 mx-auto text-primary mb-2" />
                  <span className="text-xs text-muted-foreground">Envío Gratis</span>
                </div>
                <div className="text-center">
                  <Shield className="h-6 w-6 mx-auto text-primary mb-2" />
                  <span className="text-xs text-muted-foreground">Garantía 5 Años</span>
                </div>
                <div className="text-center">
                  <RotateCcw className="h-6 w-6 mx-auto text-primary mb-2" />
                  <span className="text-xs text-muted-foreground">30 Días Devolución</span>
                </div>
              </div>

              {/* Accordion Details */}
              <Accordion type="single" collapsible className="w-full">
                <AccordionItem value="description">
                  <AccordionTrigger className="font-display font-semibold">
                    Descripción
                  </AccordionTrigger>
                  <AccordionContent>
                    <p className="text-muted-foreground leading-relaxed">
                      {product.description}
                    </p>
                  </AccordionContent>
                </AccordionItem>

                <AccordionItem value="details">
                  <AccordionTrigger className="font-display font-semibold">
                    Detalles Técnicos
                  </AccordionTrigger>
                  <AccordionContent>
                    <div className="space-y-3">
                      <div className="flex justify-between py-2 border-b border-border">
                        <span className="text-muted-foreground">Dimensiones</span>
                        <span>{product.dimensions.width} x {product.dimensions.height} x {product.dimensions.depth} cm</span>
                      </div>
                      <div className="flex justify-between py-2 border-b border-border">
                        <span className="text-muted-foreground">Materiales</span>
                        <span>{product.materials.join(', ')}</span>
                      </div>
                      {product.colors && (
                        <div className="flex justify-between py-2 border-b border-border">
                          <span className="text-muted-foreground">Colores</span>
                          <span>{product.colors.join(', ')}</span>
                        </div>
                      )}
                    </div>
                  </AccordionContent>
                </AccordionItem>

                <AccordionItem value="shipping">
                  <AccordionTrigger className="font-display font-semibold">
                    Envíos y Devoluciones
                  </AccordionTrigger>
                  <AccordionContent>
                    <div className="space-y-4 text-muted-foreground">
                      <p>
                        <strong className="text-foreground">Envío Nacional:</strong> Entrega en 5-10 días hábiles.
                        Envío gratuito en pedidos superiores a $1.000.000.
                      </p>
                      <p>
                        <strong className="text-foreground">Devoluciones:</strong> Aceptamos devoluciones dentro
                        de los 30 días siguientes a la entrega. El producto debe estar en su estado original.
                      </p>
                    </div>
                  </AccordionContent>
                </AccordionItem>
              </Accordion>

              {/* Share */}
              <div className="flex items-center gap-4">
                <span className="text-sm text-muted-foreground">Compartir:</span>
                <Button variant="ghost" size="icon">
                  <Share2 className="h-4 w-4" />
                </Button>
              </div>
            </div>
          </div>

          {/* Related Products */}
          {relatedProducts.length > 0 && (
            <section className="mt-24">
              <h2 className="font-display text-3xl font-bold mb-8">
                Productos Relacionados
              </h2>
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
                {relatedProducts.map((product, index) => (
                  <ProductCard key={product.id} product={product} index={index} />
                ))}
              </div>
            </section>
          )}
        </div>
      </main>

      {/* Sticky Mobile Add to Cart */}
      <div className="fixed bottom-0 left-0 right-0 p-4 bg-background border-t border-border lg:hidden z-40">
        <div className="flex items-center gap-4">
          <div>
            <p className="font-display text-lg font-bold">{formatPrice(product.price)}</p>
          </div>
          <Button
            className="flex-1 bg-primary text-primary-foreground"
            onClick={handleAddToCart}
            disabled={product.stock === 0}
          >
            <ShoppingCart className="mr-2 h-4 w-4" />
            Añadir al Carrito
          </Button>
        </div>
      </div>

      <Footer />
    </div>
  );
}

import { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { useAuthStore } from '@/store/authStore';
import { useWishlistStore } from '@/store/wishlistStore';
import { Navbar } from '@/components/layout/Navbar';
import { Footer } from '@/components/layout/Footer';
import { supabase } from '@/lib/supabase';
import { formatPrice } from '@/data/mock';
import {
    User,
    Package,
    Heart,
    Settings,
    MapPin,
    Clock,
    CheckCircle2,
    Truck,
    RefreshCw,
    XCircle,
    CreditCard,
    LogOut,
    ChevronRight
} from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Link, useNavigate } from 'react-router-dom';
import { cn } from '@/lib/utils';
import { Badge } from '@/components/ui/badge';

type TabType = 'perfil' | 'pedidos' | 'favoritos';

export default function ProfilePage() {
    const { user, logout } = useAuthStore();
    const { items: wishlistItems } = useWishlistStore();
    const [activeTab, setActiveTab] = useState<TabType>('perfil');
    const [orders, setOrders] = useState<any[]>([]);
    const [isLoadingOrders, setIsLoadingOrders] = useState(true);
    const navigate = useNavigate();

    useEffect(() => {
        async function fetchMyOrders() {
            if (!user) return;
            setIsLoadingOrders(true);
            const { data, error } = await supabase
                .from('orders')
                .select('*')
                .eq('user_id', user.id)
                .order('created_at', { ascending: false });

            if (!error && data) {
                setOrders(data);
            }
            setIsLoadingOrders(false);
        }
        fetchMyOrders();
    }, [user]);

    const handleLogout = async () => {
        await logout();
        navigate('/');
    };

    const menuItems = [
        { id: 'perfil' as TabType, label: 'Mis Datos', icon: User },
        { id: 'pedidos' as TabType, label: 'Mis Pedidos', icon: Package },
        { id: 'favoritos' as TabType, label: 'Mis Favoritos', icon: Heart },
    ];

    const getStatusLabel = (status: string) => {
        const map: Record<string, string> = {
            pending: 'Pendiente', processing: 'Procesando',
            shipped: 'Enviado', delivered: 'Entregado', cancelled: 'Cancelado'
        };
        return map[status] || status;
    };

    const getStatusIcon = (status: string) => {
        switch (status) {
            case 'pending': return <Clock className="h-4 w-4" />;
            case 'processing': return <RefreshCw className="h-4 w-4" />;
            case 'shipped': return <Truck className="h-4 w-4" />;
            case 'delivered': return <CheckCircle2 className="h-4 w-4" />;
            case 'cancelled': return <XCircle className="h-4 w-4" />;
            default: return <Clock className="h-4 w-4" />;
        }
    };

    const getStatusColor = (status: string) => {
        switch (status) {
            case 'pending': return 'bg-amber-500/15 text-amber-600 border-amber-500/30';
            case 'processing': return 'bg-blue-500/15 text-blue-600 border-blue-500/30';
            case 'shipped': return 'bg-purple-500/15 text-purple-600 border-purple-500/30';
            case 'delivered': return 'bg-emerald-500/15 text-emerald-600 border-emerald-500/30';
            case 'cancelled': return 'bg-red-500/15 text-red-600 border-red-500/30';
            default: return 'bg-muted text-muted-foreground';
        }
    };

    if (!user) return null;

    return (
        <div className="min-h-screen bg-muted/30 flex flex-col">
            <Navbar />

            <div className="flex-1 container mx-auto px-4 py-32">
                <h1 className="font-display text-4xl font-bold mb-8">Mi Cuenta</h1>

                <div className="flex flex-col lg:flex-row gap-8">

                    {/* Sidebar */}
                    <div className="w-full lg:w-64 flex-shrink-0">
                        <div className="bg-card border border-border rounded-xl overflow-hidden sticky top-32">
                            <div className="p-6 text-center border-b border-border bg-muted/10">
                                <div className="w-20 h-20 bg-primary/10 rounded-full flex items-center justify-center mx-auto mb-4">
                                    <User className="h-10 w-10 text-primary" />
                                </div>
                                <h2 className="font-semibold text-lg">{user.user_metadata?.name || 'Cliente'}</h2>
                                <p className="text-sm text-muted-foreground truncate">{user.email}</p>
                            </div>
                            <div className="p-3 space-y-1">
                                {menuItems.map(item => (
                                    <button
                                        key={item.id}
                                        onClick={() => setActiveTab(item.id)}
                                        className={cn(
                                            'w-full flex items-center justify-between px-4 py-3 rounded-lg text-sm transition-colors',
                                            activeTab === item.id
                                                ? 'bg-primary/10 text-primary font-medium'
                                                : 'text-muted-foreground hover:bg-muted/50 hover:text-foreground'
                                        )}
                                    >
                                        <span className="flex items-center gap-3">
                                            <item.icon className="h-4 w-4" />
                                            {item.label}
                                        </span>
                                        {(item.id === 'pedidos' && orders.length > 0) && (
                                            <span className="bg-primary text-primary-foreground text-[10px] px-2 py-0.5 rounded-full">
                                                {orders.length}
                                            </span>
                                        )}
                                        {(item.id === 'favoritos' && wishlistItems.length > 0) && (
                                            <span className="bg-gold text-charcoal font-bold text-[10px] px-2 py-0.5 rounded-full">
                                                {wishlistItems.length}
                                            </span>
                                        )}
                                    </button>
                                ))}
                            </div>
                            <div className="p-3 border-t border-border mt-2">
                                <button
                                    onClick={handleLogout}
                                    className="w-full flex items-center gap-3 px-4 py-3 rounded-lg text-sm text-destructive hover:bg-destructive/10 transition-colors"
                                >
                                    <LogOut className="h-4 w-4" />
                                    Cerrar Sesión
                                </button>
                            </div>
                        </div>
                    </div>

                    {/* Main Content */}
                    <div className="flex-1">
                        <motion.div
                            key={activeTab}
                            initial={{ opacity: 0, y: 10 }}
                            animate={{ opacity: 1, y: 0 }}
                            transition={{ duration: 0.2 }}
                        >

                            {/* PERFIL */}
                            {activeTab === 'perfil' && (
                                <div className="bg-card border border-border rounded-xl p-6 lg:p-8 space-y-8">
                                    <div>
                                        <h3 className="text-xl font-bold flex items-center gap-2 mb-1">
                                            <Settings className="h-5 w-5 text-primary" /> Información Personal
                                        </h3>
                                        <p className="text-sm text-muted-foreground mb-6">Administra tus datos básicos de la cuenta heredados de tu registro.</p>

                                        <div className="grid sm:grid-cols-2 gap-6">
                                            <div className="bg-muted/30 p-4 rounded-lg border border-border">
                                                <p className="text-xs text-muted-foreground uppercase tracking-wider font-semibold mb-1">Nombre Completo</p>
                                                <p className="font-medium">{user.user_metadata?.name || 'No especificado'}</p>
                                            </div>
                                            <div className="bg-muted/30 p-4 rounded-lg border border-border">
                                                <p className="text-xs text-muted-foreground uppercase tracking-wider font-semibold mb-1">Correo Electrónico</p>
                                                <p className="font-medium truncate">{user.email}</p>
                                            </div>
                                            <div className="bg-muted/30 p-4 rounded-lg border border-border">
                                                <p className="text-xs text-muted-foreground uppercase tracking-wider font-semibold mb-1">Rol de Cuenta</p>
                                                <p className="font-medium capitalize">{user.user_metadata?.role || 'Cliente VIP'}</p>
                                            </div>
                                            <div className="bg-muted/30 p-4 rounded-lg border border-border">
                                                <p className="text-xs text-muted-foreground uppercase tracking-wider font-semibold mb-1">Miembro desde</p>
                                                <p className="font-medium">{new Date(user.created_at || '').toLocaleDateString()}</p>
                                            </div>
                                        </div>
                                    </div>

                                    <div className="pt-6 border-t border-border">
                                        <p className="text-sm text-muted-foreground">
                                            * Para actualizar tu contraseña o correo, por favor contáctanos directamente por WhatsApp.
                                        </p>
                                    </div>
                                </div>
                            )}

                            {/* PEDIDOS */}
                            {activeTab === 'pedidos' && (
                                <div className="space-y-6">
                                    <div className="bg-card border border-border rounded-xl p-6 flex items-center justify-between">
                                        <div>
                                            <h3 className="text-xl font-bold flex items-center gap-2">
                                                <Package className="h-5 w-5 text-primary" /> Historial de Pedidos
                                            </h3>
                                            <p className="text-sm text-muted-foreground mt-1">Sigue el estado de tus compras de muebles.</p>
                                        </div>
                                    </div>

                                    {isLoadingOrders ? (
                                        <div className="text-center py-12">
                                            <RefreshCw className="h-8 w-8 animate-spin mx-auto text-muted-foreground" />
                                            <p className="mt-4 text-muted-foreground">Cargando tus pedidos...</p>
                                        </div>
                                    ) : orders.length === 0 ? (
                                        <div className="bg-card border border-border rounded-xl p-12 text-center">
                                            <Package className="h-12 w-12 text-muted-foreground/30 mx-auto mb-4" />
                                            <h4 className="text-lg font-semibold mb-2">Aún no tienes pedidos</h4>
                                            <p className="text-muted-foreground mb-6">Explora nuestro catálogo y empieza a amueblar tu hogar.</p>
                                            <Link to="/catalogo">
                                                <Button className="bg-primary text-primary-foreground">Ir al Catálogo</Button>
                                            </Link>
                                        </div>
                                    ) : (
                                        <div className="space-y-4">
                                            {orders.map((order) => (
                                                <div key={order.id} className="bg-card border border-border rounded-xl overflow-hidden hover:shadow-md transition-shadow">
                                                    <div className="p-4 sm:p-6 bg-muted/10 border-b border-border flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                                                        <div>
                                                            <div className="flex items-center gap-3 mb-1">
                                                                <span className="font-mono text-sm font-semibold">
                                                                    Pedido #{order.id.slice(0, 8).toUpperCase()}
                                                                </span>
                                                                <Badge className={cn('gap-1', getStatusColor(order.status))}>
                                                                    {getStatusIcon(order.status)}
                                                                    {getStatusLabel(order.status)}
                                                                </Badge>
                                                            </div>
                                                            <p className="text-xs text-muted-foreground flex items-center gap-1">
                                                                <Clock className="h-3 w-3" /> Realizado el {new Date(order.created_at).toLocaleDateString()}
                                                            </p>
                                                        </div>
                                                        <div className="text-left sm:text-right">
                                                            <p className="text-xs text-muted-foreground uppercase tracking-wider font-semibold">Total a pagar</p>
                                                            <p className="text-xl font-bold text-primary">{formatPrice(order.total)}</p>
                                                        </div>
                                                    </div>

                                                    <div className="p-4 sm:p-6">
                                                        <h5 className="text-sm font-semibold mb-4 flex items-center gap-2">
                                                            <Package className="h-4 w-4" /> Artículos
                                                        </h5>
                                                        <div className="space-y-3">
                                                            {(order.products || []).map((item: any, idx: number) => {
                                                                const prodName = item.product?.name || item.name || `Producto ${idx + 1}`;
                                                                const prodQty = item.quantity || 1;
                                                                const prodImg = item.product?.images?.[0] || item.image || null;
                                                                return (
                                                                    <div key={idx} className="flex items-center gap-4 p-3 bg-muted/30 rounded-lg border border-border">
                                                                        {prodImg ? (
                                                                            <img src={prodImg} alt={prodName} className="w-12 h-12 object-cover rounded-md" />
                                                                        ) : (
                                                                            <div className="w-12 h-12 bg-muted rounded-md flex items-center justify-center">
                                                                                <Package className="h-5 w-5 text-muted-foreground/50" />
                                                                            </div>
                                                                        )}
                                                                        <div className="flex-1">
                                                                            <p className="font-medium text-sm">{prodName}</p>
                                                                            <p className="text-xs text-muted-foreground">Cantidad: {prodQty}</p>
                                                                        </div>
                                                                    </div>
                                                                );
                                                            })}
                                                        </div>

                                                        <div className="mt-6 grid sm:grid-cols-2 gap-4 pt-4 border-t border-border/50">
                                                            <div>
                                                                <h5 className="text-xs font-semibold uppercase tracking-wider text-muted-foreground mb-1 flex items-center gap-1">
                                                                    <MapPin className="h-3 w-3" /> Info Envío
                                                                </h5>
                                                                <p className="text-sm line-clamp-2">{order.shipping_address}</p>
                                                            </div>
                                                            <div>
                                                                <h5 className="text-xs font-semibold uppercase tracking-wider text-muted-foreground mb-1 flex items-center gap-1">
                                                                    <CreditCard className="h-3 w-3" /> Formato de Pago
                                                                </h5>
                                                                <p className="text-sm">{order.payment_method}</p>
                                                            </div>
                                                        </div>
                                                    </div>
                                                </div>
                                            ))}
                                        </div>
                                    )}
                                </div>
                            )}

                            {/* FAVORITOS */}
                            {activeTab === 'favoritos' && (
                                <div className="bg-card border border-border rounded-xl p-6 lg:p-8 text-center min-h-[400px] flex flex-col items-center justify-center">
                                    <div className="w-20 h-20 bg-gold/10 rounded-full flex items-center justify-center mb-6">
                                        <Heart className="h-10 w-10 text-gold" />
                                    </div>
                                    <h3 className="text-2xl font-bold mb-3">Tus Favoritos</h3>
                                    <p className="text-muted-foreground max-w-md mx-auto mb-8">
                                        Actualmente tienes <strong className="text-foreground">{wishlistItems.length}</strong> productos guardados en tu lista de deseos.
                                    </p>
                                    <Link to="/favoritos">
                                        <Button size="lg" className="bg-gold text-charcoal hover:bg-gold/90 font-semibold shadow-lg">
                                            Ir a la Galería de Favoritos
                                            <ChevronRight className="h-5 w-5 ml-2" />
                                        </Button>
                                    </Link>
                                </div>
                            )}

                        </motion.div>
                    </div>
                </div>
            </div>
            <Footer />
        </div>
    );
}

import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import { supabase } from '@/lib/supabase';
import type { Product, BlogPost, Order } from '@/data/mock';

// Interfaces
interface ContactInfo {
  phone: string;
  email: string;
  address: string;
  whatsapp: string;
  schedule: string;
  socialLinks: {
    facebook: string;
    instagram: string;
    pinterest: string;
  };
}

export interface StoreSettings {
  storeName: string;
  storeDescription: string;
  logoUrl: string;
  currency: string;
  taxRate: number;
  freeShippingThreshold: number;
  metaTitle: string;
  metaDescription: string;
  shippingPolicy: string;
  returnPolicy: string;
  privacyPolicy: string;
}

interface HomePageContent {
  heroTitle: string;
  heroSubtitle: string;
  heroImage: string;
  favoritesTitle: string;
  bestSellersTitle: string;
  newArrivalsTitle: string;
  designsTitle: string;
  heroBadgeText: string;
}

export interface Quote {
  id: string;
  userName: string;
  userEmail: string;
  userPhone: string;
  userCity: string;
  furnitureType: string;
  width?: string;
  height?: string;
  depth?: string;
  material?: string;
  description: string;
  images: string[]; // Base64 strings for local persistence
  status: 'pending' | 'reviewed' | 'contacted' | 'archived';
  createdAt: string;
}

interface AdminState {
  products: Product[];
  blogPosts: BlogPost[];
  contactInfo: ContactInfo;
  homePageContent: HomePageContent;
  storeSettings: StoreSettings;
  isLoadingProducts: boolean;
  isLoadingBlog: boolean;
  isLoadingOrders: boolean;
  isLoadingSettings: boolean;

  // Settings
  fetchSettings: () => Promise<void>;

  // Products CRUD
  fetchProducts: () => Promise<void>;
  addProduct: (product: Product) => Promise<void>;
  updateProduct: (id: string, product: Partial<Product>) => Promise<void>;
  deleteProduct: (id: string) => Promise<void>;

  // Blog CRUD
  fetchBlogPosts: () => Promise<void>;
  addBlogPost: (post: BlogPost) => Promise<void>;
  updateBlogPost: (id: string, post: Partial<BlogPost>) => Promise<void>;
  deleteBlogPost: (id: string) => Promise<void>;

  // Orders
  orders: any[]; // Usaremos any por ahora para no atarlos extrechamente a la forma del mock que es un poco distinta a la de Supabase
  fetchOrders: () => Promise<void>;
  updateOrderStatus: (id: string, status: string) => Promise<void>;

  // Contact, Home, Store Settings (Ahora se guardan en Supabase)
  updateContactInfo: (info: Partial<ContactInfo>) => Promise<void>;
  updateHomePageContent: (content: Partial<HomePageContent>) => Promise<void>;
  updateStoreSettings: (settings: Partial<StoreSettings>) => Promise<void>;

  // Quotes (Cotizaciones)
  quotes: Quote[];
  addQuote: (quote: Quote) => void;
  updateQuoteStatus: (id: string, status: Quote['status']) => void;
  deleteQuote: (id: string) => void;
}

